  "inlineSchema": "// prisma/schema.prisma\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ----------------------------------------------------\n// ENUMS PARA INTEGRIDAD FINANCIERA Y FACTURACIÓN\n// ----------------------------------------------------\nenum TransactionType {\n  INCOME\n  EXPENSE\n}\n\nenum TransactionStatus {\n  PENDING\n  PAID\n  CANCELLED\n}\n\nenum RecurrenceFrequency {\n  MONTHLY\n  ANNUAL\n}\n\n// NUEVO: Enum para el estado de las facturas (Borradores vs SAT)\nenum InvoiceStatus {\n  DRAFT // Borrador (No timbrada)\n  TIMBRADA // Aprobada por el SAT\n  CANCELLED // Cancelada en el SAT\n}\n\n// 👤 MÓDULO AUTH\nmodel User {\n  id           String   @id @default(uuid())\n  username     String   @unique\n  passwordHash String\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n}\n\n// 📦 MÓDULO SERVICIOS Y CLIENTES\nmodel Service {\n  id           String                 @id @default(uuid())\n  name         String                 @unique\n  isActive     Boolean                @default(true)\n  transactions FinancialTransaction[]\n  createdAt    DateTime               @default(now())\n  updatedAt    DateTime               @updatedAt\n}\n\nmodel Client {\n  id            String                 @id @default(uuid())\n  firstName     String\n  lastName1     String\n  lastName2     String?\n  rfc           String                 @unique\n  phone         String?\n  email         String?\n  transactions  FinancialTransaction[]\n  subscriptions Subscription[]\n  createdAt     DateTime               @default(now())\n  updatedAt     DateTime               @updatedAt\n}\n\n// 🔄 MÓDULO SUSCRIPCIONES\nmodel Subscription {\n  id          String              @id @default(uuid())\n  clientId    String\n  client      Client              @relation(fields: [clientId], references: [id])\n  serviceName String\n  amount      Decimal             @db.Decimal(10, 2)\n  frequency   RecurrenceFrequency\n  startDate   DateTime\n  nextBilling DateTime\n  isActive    Boolean             @default(true)\n  createdAt   DateTime            @default(now())\n  updatedAt   DateTime            @updatedAt\n}\n\n// ⏰ MÓDULO RECORDATORIOS\nmodel Reminder {\n  id            String   @id @default(uuid())\n  title         String\n  description   String?\n  dueDate       DateTime\n  isCompleted   Boolean  @default(false)\n  notified1Day  Boolean  @default(false)\n  notified7Days Boolean  @default(false)\n  createdAt     DateTime @default(now())\n  updatedAt     DateTime @updatedAt\n}\n\n// 💰 MÓDULO FINANZAS\nmodel FinancialTransaction {\n  id          String            @id @default(uuid())\n  type        TransactionType\n  amount      Decimal           @db.Decimal(10, 2)\n  description String\n  date        DateTime          @default(now())\n  status      TransactionStatus @default(PENDING)\n\n  clientId String?\n  client   Client? @relation(fields: [clientId], references: [id])\n\n  serviceId String?\n  service   Service? @relation(fields: [serviceId], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// 📊 MÓDULO REPORTES\nmodel Report {\n  id          String   @id @default(uuid())\n  title       String\n  type        String\n  dataUrl     String?\n  generatedAt DateTime @default(now())\n  createdAt   DateTime @default(now())\n}\n\n// ====================================================\n// 🧾 MÓDULO FACTURACIÓN ELECTRÓNICA (CFDI 4.0)\n// ====================================================\n\nmodel BillingEmisor {\n  id            String  @id @default(uuid())\n  rfc           String  @unique\n  razonSocial   String\n  regimenFiscal String\n  codigoPostal  String\n  email         String?\n  logoUrl       String? // <-- NUEVO: Ruta del logotipo para el PDF\n\n  // Relaciones (Para que cada Emisor tenga sus propios clientes, productos y facturas)\n  receptores BillingReceptor[]\n  conceptos  BillingConcept[]\n  facturas   Invoice[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel BillingReceptor {\n  id             String  @id @default(uuid())\n  rfc            String  @unique\n  razonSocial    String\n  usoCfdiDefault String\n  regimenFiscal  String\n  codigoPostal   String\n  email          String?\n\n  emisorId String? // <-- NUEVO: Emisor al que pertenece este cliente\n  emisor   BillingEmisor? @relation(fields: [emisorId], references: [id])\n\n  invoices  Invoice[]\n  createdAt DateTime  @default(now())\n  updatedAt DateTime  @updatedAt\n}\n\nmodel BillingConcept {\n  id                 String  @id @default(uuid())\n  claveProdServ      String\n  noIdentificacion   String?\n  descripcion        String\n  claveUnidad        String  @default(\"E48\")\n  unidad             String  @default(\"Servicio\")\n  valorUnitario      Decimal @db.Decimal(10, 2)\n  impuestoTrasladado Decimal @default(0.1600) @db.Decimal(5, 4)\n  objetoImpuesto     String  @default(\"02\")\n\n  emisorId String? // <-- NUEVO: Emisor al que pertenece el producto\n  emisor   BillingEmisor? @relation(fields: [emisorId], references: [id])\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\nmodel Invoice {\n  id String @id @default(uuid())\n\n  emisorId String // <-- NUEVO: Referencia obligatoria al Emisor\n  emisor   BillingEmisor @relation(fields: [emisorId], references: [id])\n\n  receptorId String\n  receptor   BillingReceptor @relation(fields: [receptorId], references: [id])\n\n  tipoComprobante String\n  metodoPago      String\n  formaPago       String\n  moneda          String  @default(\"MXN\")\n  exportacion     String  @default(\"01\")\n  serie           String?\n  folio           String?\n\n  subtotal         Decimal @db.Decimal(10, 2)\n  descuento        Decimal @default(0) @db.Decimal(10, 2)\n  totalTraslados   Decimal @default(0) @db.Decimal(10, 2)\n  totalRetenciones Decimal @default(0) @db.Decimal(10, 2)\n  total            Decimal @db.Decimal(10, 2)\n\n  // NUEVO: Control de Estados y Archivos SAT\n  status        InvoiceStatus @default(DRAFT)\n  uuidFacturama String?       @unique\n  fechaEmision  DateTime      @default(now())\n  fechaTimbrado DateTime?\n  xmlUrl        String?\n  pdfUrl        String?\n\n  // Relación con las partidas (conceptos) de esta factura\n  items InvoiceItem[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n\n// NUEVO: Partidas Individuales por Factura\nmodel InvoiceItem {\n  id String @id @default(uuid())\n\n  invoiceId String\n  invoice   Invoice @relation(fields: [invoiceId], references: [id], onDelete: Cascade)\n\n  claveProdServ    String\n  noIdentificacion String?\n  descripcion      String\n  claveUnidad      String\n  unidad           String\n  cantidad         Decimal @db.Decimal(10, 2)\n  valorUnitario    Decimal @db.Decimal(10, 2)\n  importe          Decimal @db.Decimal(10, 2)\n  descuento        Decimal @default(0) @db.Decimal(10, 2)\n  objetoImpuesto   String\n\n  // JSON Flexible para guardar los impuestos de este concepto exacto (IVA, ISR, IEPS)\n  impuestosJson Json?\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n}\n",
